"use client";

import { useState } from "react";
import { X, MapPin, Phone, Building2 } from "lucide-react";
import { searchCities } from "@/lib/uk-cities";
import { geocodePostcode } from "@/lib/geolocation";

interface OnboardingModalProps {
  isOpen: boolean;
  garageId: string;
  onClose: () => void;
  onComplete: () => void;
}

export default function OnboardingModal({
  isOpen,
  garageId,
  onClose,
  onComplete,
}: OnboardingModalProps) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [step, setStep] = useState(1);
  const [verifying, setVerifying] = useState(false);
  const [citySuggestions, setCitySuggestions] = useState<string[]>([]);
  const [showCitySuggestions, setShowCitySuggestions] = useState(false);

  const [form, setForm] = useState({
    phone: "+44",
    address: "",
    postcode: "",
    city: "",
  });

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let value = e.target.value;
    if (!value.startsWith("+44")) {
      value = "+44" + value.replace(/^\+?44/, "");
    }
    setForm({ ...form, phone: value });
  };

  const handleCityChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setForm({ ...form, city: value });
    
    if (value.length > 2) {
      const matches = searchCities(value);
      setCitySuggestions(matches);
      setShowCitySuggestions(matches.length > 0);
    } else {
      setShowCitySuggestions(false);
    }
  };

  const handlePostcodeVerify = async () => {
    if (!form.postcode || form.postcode.length < 5) {
      setError("Please enter a valid UK postcode");
      return;
    }

    setVerifying(true);
    setError(null);

    try {
      const result = await geocodePostcode(form.postcode);
      if (result.city && result.county) {
        setForm({ ...form, city: result.city, address: result.address || "" });
        setError(null);
      } else {
        setError("Postcode not found. Please check and try again.");
      }
    } catch (err) {
      setError("Failed to verify postcode. Please enter city manually.");
    } finally {
      setVerifying(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (step === 1) {
      if (!form.phone.replace("+44", "").trim()) {
        setError("Please enter a phone number");
        return;
      }
      setStep(2);
      return;
    }

    if (!form.address.trim() || !form.city.trim() || !form.postcode.trim()) {
      setError("Please complete all location fields");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await fetch(`/api/garages/${garageId}`, {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          phone: form.phone,
          address: form.address,
          postcode: form.postcode,
          city: form.city,
        }),
      });

      if (!response.ok) {
        const data = await response.json();
        setError(data.error || "Failed to save garage details");
        return;
      }

      // Update localStorage
      const cached = localStorage.getItem("garage-data");
      if (cached) {
        const garage = JSON.parse(cached);
        garage.phone = form.phone;
        garage.address = form.address;
        garage.postcode = form.postcode;
        garage.city = form.city;
        localStorage.setItem("garage-data", JSON.stringify(garage));
      }

      onComplete();
    } catch (err) {
      console.error("Error saving garage:", err);
      setError("An error occurred while saving details");
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl max-w-md w-full">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-slate-200">
          <h2 className="text-2xl font-bold text-slate-900">
            {step === 1 ? "Connect with Customers" : "Set Your Location"}
          </h2>
          <button
            onClick={onClose}
            className="text-slate-500 hover:text-slate-700"
          >
            <X size={24} />
          </button>
        </div>

        {/* Content */}
        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          {error && (
            <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
              {error}
            </div>
          )}

          {step === 1 ? (
            // Step 1: Phone
            <div className="space-y-4">
              <p className="text-slate-600 text-sm">
                Help customers reach you. You can update this anytime.
              </p>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">
                  <Phone size={16} className="inline mr-2" />
                  Phone Number
                </label>
                <input
                  type="tel"
                  value={form.phone}
                  onChange={handlePhoneChange}
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="+44 7000 000000"
                />
              </div>
              <p className="text-xs text-slate-500">
                We'll use this to display on your garage profile and send notifications.
              </p>
            </div>
          ) : (
            // Step 2: Location
            <div className="space-y-4">
              <p className="text-slate-600 text-sm">
                Help customers find you. Search by postcode or enter manually.
              </p>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">
                  <MapPin size={16} className="inline mr-2" />
                  UK Postcode
                </label>
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={form.postcode}
                    onChange={(e) => setForm({ ...form, postcode: e.target.value.toUpperCase() })}
                    className="flex-1 px-4 py-3 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="e.g., SW1A 1AA"
                  />
                  <button
                    type="button"
                    onClick={handlePostcodeVerify}
                    disabled={verifying}
                    className="px-4 py-3 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-lg transition-colors disabled:opacity-50"
                  >
                    {verifying ? "..." : "Verify"}
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">
                  <Building2 size={16} className="inline mr-2" />
                  Address
                </label>
                <input
                  type="text"
                  value={form.address}
                  onChange={(e) => setForm({ ...form, address: e.target.value })}
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="e.g., 123 Market Street"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">
                  City
                </label>
                <div className="relative">
                  <input
                    type="text"
                    value={form.city}
                    onChange={handleCityChange}
                    onFocus={() => form.city.length > 2 && setShowCitySuggestions(true)}
                    className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="e.g., London"
                  />
                  {showCitySuggestions && citySuggestions.length > 0 && (
                    <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-300 rounded-lg shadow-lg z-10 max-h-48 overflow-y-auto">
                      {citySuggestions.map((city) => (
                        <button
                          key={city}
                          type="button"
                          onClick={() => {
                            setForm({ ...form, city });
                            setShowCitySuggestions(false);
                          }}
                          className="w-full text-left px-4 py-2 hover:bg-blue-50 text-slate-700 transition-colors"
                        >
                          {city}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}

          {/* Actions */}
          <div className="flex gap-3 pt-4">
            {step === 2 && (
              <button
                type="button"
                onClick={() => setStep(1)}
                disabled={loading}
                className="flex-1 px-4 py-3 bg-slate-200 hover:bg-slate-300 text-slate-700 font-semibold rounded-lg transition-colors disabled:opacity-50"
              >
                Back
              </button>
            )}
            <button
              type="submit"
              disabled={loading}
              className="flex-1 px-4 py-3 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-lg transition-colors disabled:opacity-50"
            >
              {step === 1 ? "Next" : loading ? "Saving..." : "Complete Setup"}
            </button>
          </div>

          <p className="text-xs text-slate-500 text-center">
            You can update these details anytime in Settings.
          </p>
        </form>
      </div>
    </div>
  );
}
